section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/audience-segmentation.json",
  "title": "Audience Segmentation",
  "type": "object",
  "required": [
    "artefact_id",
    "dimensions",
    "segments",
    "segment_scores",
    "target_segment",
    "icp",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "dimensions": {
      "type": "array",
      "description": "2-3 dimensions chosen with rationale",
      "minItems": 1
    },
    "segments": {
      "type": "array",
      "description": "2-5 scored segments",
      "minItems": 1
    },
    "segment_scores": {
      "type": "object",
      "description": "segment \u2192 {size, accessibility, fit, score:0-100}"
    },
    "target_segment": {
      "type": "string",
      "description": "chosen single segment + rationale",
      "minLength": 1
    },
    "icp": {
      "type": "object",
      "description": "profile of the target segment"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "audience-segmentation-2026-05-23",
  "dimensions": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "segments": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "segment_scores": {
    "key": "value"
  },
  "target_segment": "draft",
  "icp": {
    "key": "value"
  },
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
